{
  "code": "export default async function({ page }) {
  const TBR_USERNAME = 'neborides@gmail.com';
  const TBR_PASSWORD = 'j28yA1wzK7KA';

  // Go to login page
  await page.goto('https://system.tbrglobal.com/login', { waitUntil: 'networkidle0', timeout: 30000 });

  // Wait for and fill login form
  await page.waitForSelector('#loginForm_securityUserEmailAddress', { timeout: 10000 });
  await page.type('#loginForm_securityUserEmailAddress', TBR_USERNAME);
  await page.type('#loginForm_securityUserPassword', TBR_PASSWORD);

  // Click login
  await Promise.all([
    page.waitForNavigation({ waitUntil: 'networkidle0', timeout: 30000 }),
    page.click('input[type=submit][value=Login]')
  ]);

  // Navigate to supplier page
  await page.goto('https://system.tbrglobal.com/supplier/', { waitUntil: 'networkidle0', timeout: 30000 });

  // Get page info
  const currentUrl = page.url();
  const pageTitle = await page.title();

  // Get page HTML for debugging
  const pageHtml = await page.content();

  // Extract trips from list view
  const trips = await page.evaluate(() => {
    const results = [];

    // Try multiple selectors for trip rows
    const rows = document.querySelectorAll('table tbody tr, .trip-row, .booking-row, .reservation-row, tr[data-id]');

    rows.forEach((row, index) => {
      const cells = row.querySelectorAll('td');
      const getText = (el) => el?.textContent?.trim() || '';
      const getCell = (i) => getText(cells[i]);

      // Try to extract data from visible columns
      const trip = {
        tbrTripId: row.dataset?.id || row.getAttribute('data-id') || getCell(0) || 'TBR-' + Date.now() + '-' + index,
        status: getCell(1) || getText(row.querySelector('.status')),
        passengerName: getCell(2) || getText(row.querySelector('.passenger, .name, .client')),
        pickupDatetime: getCell(3) || getText(row.querySelector('.date, .pickup-date')),
        pickupAddress: getCell(4) || getText(row.querySelector('.pickup, .from')),
        dropoffAddress: getCell(5) || getText(row.querySelector('.dropoff, .to')),
        vehicleType: getCell(6) || getText(row.querySelector('.vehicle')),
        fareAmount: parseFloat((getCell(7) || getText(row.querySelector('.fare, .price'))).replace(/[^0-9.]/g, '')) || null,
        passengerPhone: null,
        passengerEmail: null,
        passengerCount: 1,
        flightNumber: null,
        notes: null
      };

      // Only add if we have some valid data
      if (trip.tbrTripId && trip.tbrTripId !== 'TBR-' + Date.now() + '-' + index) {
        results.push(trip);
      }
    });

    return results;
  });

  return { 
    trips,
    count: trips.length,
    currentUrl,
    pageTitle,
    htmlPreview: pageHtml.substring(0, 3000),
    scrapedAt: new Date().toISOString()
  };
}"
}

