const data = $input.first().json;
const trips = data.trips || [];

console.log(`Scraped ${trips.length} trips from TBR Global`);
console.log('Current URL:', data.currentUrl);
console.log('Page Title:', data.pageTitle);

if (trips.length === 0) {
  // Return debug info so we can see what's on the page
  return [{ json: { trips: [], source: 'browserless-scraper', debug: { currentUrl: data.currentUrl, pageTitle: data.pageTitle, htmlPreview: data.htmlPreview } } }];
}

const formatted = trips.map(t => ({
  tbrTripId: t.tbrTripId,
  status: t.status || 'Pending',
  passengerName: t.passengerName || 'Unknown',
  passengerPhone: t.passengerPhone || null,
  passengerEmail: t.passengerEmail || null,
  passengerCount: t.passengerCount || 1,
  pickupDatetime: t.pickupDatetime,
  pickupAddress: t.pickupAddress,
  dropoffAddress: t.dropoffAddress,
  vehicleType: t.vehicleType || 'Sedan',
  flightNumber: t.flightNumber || null,
  notes: t.notes || null,
  fareAmount: t.fareAmount
}));

return [{ json: { trips: formatted, source: 'browserless-scraper' } }];

const response = $input.first().json;
console.log('TBR Sync Result:', response);
return [{ json: { success: true, ...response } }];
